 26→import { join } from "path";
 27→import { is } from "@electron-toolkit/utils";
 28→
 29→const views = new Map<string, WebContentsView>();
 30→const viewBounds = new Map<string, Electron.Rectangle>();
 31→
 32→/** Reference to the detached browser window (only one at a time) */
 33→let detachedWindow: BrowserWindow | null = null;
