 37→  // Create a new browser view
 38→  // Renderer calls: invoke("create_browser_webview", { label, url, x, y, width, height, windowLabel })
 39→  // -------------------------------------------------------------------------
 40→
 41→  ipcMain.handle(
 42→    "create_browser_webview",
 43→    (
 44→      _e,
 45→      {
 46→        label,
 47→        url,
 48→        x,
 49→        y,
 50→        width,
 51→        height,
 52→      }: {
 53→        label: string;
 54→        url: string;
 55→        x: number;
 56→        y: number;
 57→        width: number;
 58→        height: number;
 59→        windowLabel?: string;
 60→      }
 61→    ) => {
 62→      const mainWindow = BrowserWindow.getAllWindows()[0];
 63→      if (!mainWindow) return;
 64→
 65→      // Clean up existing view with same label
 66→      const existing = views.get(label);
 67→      if (existing) {
 68→        mainWindow.contentView.removeChildView(existing);
 69→        (existing.webContents as any).destroy?.();
 70→        views.delete(label);
 71→      }
 72→
 73→      // getBoundingClientRect() returns CSS-pixel coordinates, but
 74→      // WebContentsView.setBounds() operates in the window's native coordinate
 75→      // space. When the user zooms the renderer (Cmd+/Cmd-), CSS pixels diverge
 76→      // from window points by the zoom factor — multiply to correct.
 77→      const zoomFactor = mainWindow.webContents.getZoomFactor();
 78→      const bounds = {
 79→        x: Math.round(x * zoomFactor),
 80→        y: Math.round(y * zoomFactor),
 81→        width: Math.round(Math.max(width * zoomFactor, 100)),
 82→        height: Math.round(Math.max(height * zoomFactor, 100)),
 83→      };
 84→
 85→      const view = new WebContentsView({
 86→        webPreferences: {
 87→          partition: `persist:browser-${label}`,
 88→          contextIsolation: true,
 89→          sandbox: false, // ESM preload (.mjs) requires sandbox: false
 90→          preload: join(__dirname, "../preload/browser-preload.mjs"),
 91→        },
 92→      });
 93→
 94→      // Add as a child of contentView. Currently renders on top of main
 95→      // WebContents (same as old BrowserView behavior). To render BEHIND
 96→      // the DOM (like Cursor/VS Code), use addChildView(view, 0) and make
 97→      // the browser panel area transparent — tracked as a follow-up.
 98→      mainWindow.contentView.addChildView(view);
 99→      view.setBounds(bounds);
100→      views.set(label, view);
101→
102→      // Register event listeners BEFORE loadURL to avoid race conditions.
103→      // loadURL() triggers loading events that must be captured.
104→      //
105→      // Event semantics:
106→      //   did-start-loading  — any frame starts (main + iframes/ads)
107→      //   did-stop-loading   — ALL frames finished (tab spinner stops)
108→      //   did-finish-load    — main frame only
109→      //   did-fail-load      — main frame navigation failure
110→      //
111→      // We use did-start-loading + did-stop-loading to match browser tab
112→      // spinner behavior. did-finish-load fires before subresources are
113→      // done, and did-start-loading fires for iframes too — using
114→      // did-stop-loading as "finished" ensures loading state clears once
115→      // everything is truly done (no stuck spinner from ad iframes).
116→      view.webContents.on("did-start-loading", () => {
117→        mainWindow.webContents.send("browser:page-load", {
118→          label,
119→          url: view.webContents.getURL(),
120→          event: "started",
121→        });
122→      });
123→
124→      view.webContents.on("did-stop-loading", () => {
125→        mainWindow.webContents.send("browser:page-load", {
126→          label,
127→          url: view.webContents.getURL(),
128→          event: "finished",
129→        });
130→      });
131→
132→      view.webContents.on(
133→        "did-fail-load",
134→        (_event, errorCode, errorDescription, _url, isMainFrame) => {
135→          // Only report main frame failures — subframe failures (ads, iframes)
136→          // shouldn't show as page-level errors.
137→          // ERR_ABORTED (-3) fires during redirects and canceled navigations — not a real failure.
138→          if (!isMainFrame || errorCode === -3) return;
139→          mainWindow.webContents.send("browser:page-load", {
140→            label,
141→            url: view.webContents.getURL(),
142→            event: "failed",
143→            error: { code: errorCode, description: errorDescription },
144→          });
145→        }
146→      );
147→
148→      view.webContents.on("page-title-updated", (_, title) => {
149→        mainWindow.webContents.send("browser:title-changed", { label, title });
150→      });
151→
152→      view.webContents.on("did-navigate", () => {
153→        mainWindow.webContents.send("browser:url-change", {
154→          label,
155→          url: view.webContents.getURL(),
156→        });
157→      });
158→
159→      view.webContents.on("did-navigate-in-page", () => {
160→        mainWindow.webContents.send("browser:url-change", {
161→          label,
162→          url: view.webContents.getURL(),
163→        });
164→      });
165→
166→      // TODO: Network request tracking — disabled until renderer listener is wired.
167→      // The events were being sent but nothing consumed them (wasted IPC traffic).
168→
169→      // Gracefully handle certificate errors for localhost dev servers.
170→      // Self-signed certs on localhost/127.0.0.1 are accepted — all other
171→      // cert errors are rejected (navigation will fail).
172→      view.webContents.on("certificate-error", (event, _url, _error, _certificate, callback) => {
173→        try {
174→          const parsed = new URL(_url);
175→          if (parsed.hostname === "localhost" || parsed.hostname === "127.0.0.1") {
176→            event.preventDefault();
177→            callback(true); // Accept for localhost
178→            return;
179→          }
180→        } catch {
181→          // Malformed URL — fall through to reject
182→        }
183→        callback(false);
184→      });
185→
186→      // Open external links in system browser (only allow http/https)
187→      view.webContents.setWindowOpenHandler(({ url: linkUrl }) => {
188→        try {
189→          const parsed = new URL(linkUrl);
190→          if (parsed.protocol === "http:" || parsed.protocol === "https:") {
191→            shell.openExternal(linkUrl);
192→          }
193→        } catch {
194→          // Ignore malformed URLs
195→        }
196→        return { action: "deny" };
197→      });
198→
199→      // Handle keyboard shortcuts from the browser preload
200→      view.webContents.on("ipc-message", (_event, channel, data) => {
201→        if (channel === "browser:keyboard-shortcut") {
202→          const { shortcut } = data as { shortcut: string };
203→          if (shortcut === "reload") {
204→            view.webContents.reload();
205→          } else if (shortcut === "focus-url-bar") {
206→            // Forward to renderer so the URL bar can be focused
207→            mainWindow.webContents.send("browser:keyboard-shortcut", { shortcut });
208→          }
209→        }
210→      });
211→
212→      // Start navigation AFTER all listeners are attached
213→      view.webContents.loadURL(url);
214→    }
215→  );
216→
217→  // -------------------------------------------------------------------------
218→  // Navigation
219→  // Renderer calls: invoke("navigate_browser_webview", { label, url })
220→  // -------------------------------------------------------------------------
221→
222→  ipcMain.handle(
223→    "navigate_browser_webview",
224→    (_e, { label, url }: { label: string; url: string }) => {
225→      views.get(label)?.webContents.loadURL(url);
226→    }
227→  );
228→
229→  // -------------------------------------------------------------------------
230→  // JavaScript evaluation (fire-and-forget)
231→  // Renderer calls: invoke("eval_browser_webview", { label, js })
232→  // Used by BrowserTab.tsx to inject automation scripts into the webview.
233→  // -------------------------------------------------------------------------
234→
235→  ipcMain.handle(
236→    "eval_browser_webview",
237→    async (_e, { label, js }: { label: string; js: string }) => {
238→      const view = views.get(label);
239→      if (!view) return null;
240→      try {
241→        return await view.webContents.executeJavaScript(js);
242→      } catch (err) {
243→        console.error(`[browser:eval] Error in view "${label}":`, err);
244→        return null;
245→      }
246→    }
247→  );
248→
249→  // -------------------------------------------------------------------------
250→  // JavaScript evaluation (with result capture)
251→  // Renderer calls: invoke("eval_browser_webview_with_result", { label, js })
252→  // Used by BrowserTab.tsx for console drain and inspect mode event drain.
253→  // -------------------------------------------------------------------------
254→
255→  ipcMain.handle(
256→    "eval_browser_webview_with_result",
257→    async (_e, { label, js }: { label: string; js: string }) => {
258→      const view = views.get(label);
259→      if (!view) return null;
260→      try {
261→        return await view.webContents.executeJavaScript(js);
262→      } catch (err) {
263→        console.error(`[BrowserView] eval failed for "${label}":`, err);
264→        return null;
265→      }
266→    }
267→  );
268→
269→  // -------------------------------------------------------------------------
270→  // Screenshot
271→  // Renderer calls: invoke("screenshot_browser_webview", { label, x?, y?, width?, height? })
272→  // Supports optional crop rectangle; omit for full page capture.
273→  // -------------------------------------------------------------------------
274→
275→  ipcMain.handle(
276→    "screenshot_browser_webview",
277→    async (
278→      _e,
279→      {
280→        label,
281→        x,
282→        y,
283→        width,
284→        height,
285→      }: {
286→        label: string;
287→        x?: number;
288→        y?: number;
289→        width?: number;
290→        height?: number;
291→      }
292→    ) => {
293→      const view = views.get(label);
294→      if (!view) return null;
295→      try {
296→        let image;
297→        if (x !== undefined && y !== undefined && width !== undefined && height !== undefined) {
298→          image = await view.webContents.capturePage({
299→            x: Math.round(x),
300→            y: Math.round(y),
301→            width: Math.round(width),
302→            height: Math.round(height),
303→          });
304→        } else {
305→          image = await view.webContents.capturePage();
306→        }
307→        return image.toDataURL();
308→      } catch (err) {
309→        console.error(`[BrowserView] screenshot failed for "${label}":`, err);
310→        return null;
311→      }
312→    }
313→  );
314→
315→  // -------------------------------------------------------------------------
316→  // DevTools
317→  // Renderer calls: invoke("open_browser_devtools", { label })
318→  //                 invoke("close_browser_devtools", { label })
319→  // -------------------------------------------------------------------------
320→
321→  ipcMain.handle(
322→    "open_browser_devtools",
323→    (_e, { label, mode }: { label: string; mode?: "right" | "bottom" | "detach" | "undocked" }) => {
324→      views.get(label)?.webContents.openDevTools({ mode: mode ?? "bottom" });
325→    }
326→  );
327→
328→  ipcMain.handle("close_browser_devtools", (_e, { label }: { label: string }) => {
329→    const view = views.get(label);
330→    if (view?.webContents.isDevToolsOpened()) {
331→      view.webContents.closeDevTools();
332→    }
333→  });
334→
335→  // -------------------------------------------------------------------------
336→  // Bounds / visibility
337→  // Renderer calls: invoke("set_browser_webview_bounds", { label, x, y, width, height })
338→  //                 invoke("show_browser_webview", { label })
339→  //                 invoke("hide_browser_webview", { label })
340→  //                 invoke("close_browser_webview", { label })
341→  //                 invoke("reload_browser_webview", { label })
342→  // -------------------------------------------------------------------------
343→
344→  ipcMain.handle(
345→    "set_browser_webview_bounds",
346→    (
347→      _e,
348→      {
349→        label,
350→        x,
351→        y,
352→        width,
353→        height,
354→      }: {
355→        label: string;
356→        x: number;
357→        y: number;
358→        width: number;
359→        height: number;
360→      }
361→    ) => {
362→      // CSS-pixel → window-point conversion (see create_browser_webview comment)
363→      const mainWindow = BrowserWindow.getAllWindows()[0];
364→      const zoomFactor = mainWindow?.webContents.getZoomFactor() ?? 1;
365→      const bounds = {
366→        x: Math.round(x * zoomFactor),
367→        y: Math.round(y * zoomFactor),
368→        width: Math.round(width * zoomFactor),
369→        height: Math.round(height * zoomFactor),
370→      };
371→      const view = views.get(label);
372→      if (view) {
373→        view.setBounds(bounds);
374→        // Also save to viewBounds so show() uses the latest position
375→        // (important when setBounds is called while the view is hidden/detached)
376→        viewBounds.set(label, bounds);
377→      }
378→    }
379→  );
380→
381→  ipcMain.handle("show_browser_webview", (_e, { label }: { label: string }) => {
382→    const mainWindow = BrowserWindow.getAllWindows()[0];
383→    const view = views.get(label);
384→    if (mainWindow && view) {
385→      // Ensure view is in the contentView hierarchy
386→      const children = mainWindow.contentView.children;
387→      if (!children.includes(view)) {
388→        mainWindow.contentView.addChildView(view);
389→      }
390→      view.setVisible(true);
391→      const savedBounds = viewBounds.get(label);
392→      if (savedBounds) {
393→        view.setBounds(savedBounds);
394→      }
395→    }
396→  });
397→
398→  ipcMain.handle("hide_browser_webview", (_e, { label }: { label: string }) => {
399→    const view = views.get(label);
400→    if (view) {
401→      viewBounds.set(label, view.getBounds());
402→      view.setVisible(false);
403→    }
404→  });
405→
406→  // Hide ALL browser views at once — called when switching workspaces
407→  // or navigating to the welcome screen to ensure no stale native overlays.
408→  ipcMain.handle("hide_all_browser_webviews", () => {
409→    for (const [label, view] of views) {
410→      viewBounds.set(label, view.getBounds());
411→      view.setVisible(false);
412→    }
413→  });
414→
415→  ipcMain.handle("close_browser_webview", (_e, { label }: { label: string }) => {
416→    const view = views.get(label);
417→    if (!view) return;
418→    const mainWindow = BrowserWindow.getAllWindows()[0];
419→    if (mainWindow) {
420→      mainWindow.contentView.removeChildView(view);
421→    }
422→    (view.webContents as any).destroy?.();
423→    views.delete(label);
424→    viewBounds.delete(label);
425→  });
426→
427→  ipcMain.handle("reload_browser_webview", (_e, { label }: { label: string }) => {
428→    views.get(label)?.webContents.reload();
429→  });
430→
431→  // -------------------------------------------------------------------------
432→  // Cookie management (preload browserInvoke calls "browser:cookies:set/get")
433→  // Keep these with the browser: prefix for the preload's browserInvoke()
434→  // -------------------------------------------------------------------------
435→
436→  ipcMain.handle(
437→    "browser:cookies:set",
438→    async (_e, { label, cookies }: { label: string; cookies: Electron.CookiesSetDetails[] }) => {
439→      const ses = views.get(label)?.webContents.session;
440→      if (!ses) return;
441→      for (const cookie of cookies) {
442→        await ses.cookies.set(cookie);
443→      }
444→    }
445→  );
446→
447→  ipcMain.handle(
448→    "browser:cookies:get",
449→    async (_e, { label, url }: { label: string; url: string }) => {
450→      const ses = views.get(label)?.webContents.session;
451→      if (!ses) return [];
452→      return ses.cookies.get({ url });
453→    }
454→  );
455→
456→  // -------------------------------------------------------------------------
457→  // Get URL / title (preload browserInvoke calls "browser:getURL" / "browser:getTitle")
458→  // -------------------------------------------------------------------------
459→
460→  ipcMain.handle("browser:getURL", (_e, { label }: { label: string }) => {
461→    return views.get(label)?.webContents.getURL() ?? null;
462→  });
463→
464→  ipcMain.handle("browser:getTitle", (_e, { label }: { label: string }) => {
465→    return views.get(label)?.webContents.getTitle() ?? null;
466→  });
467→
468→  // -------------------------------------------------------------------------
469→  // Back / Forward (preload browserInvoke calls "browser:back" / "browser:forward")
470→  // -------------------------------------------------------------------------
471→
472→  ipcMain.handle("browser:back", (_e, { label }: { label: string }) => {
473→    const view = views.get(label);
474→    if (view?.webContents.canGoBack()) {
475→      view.webContents.goBack();
476→    }
477→  });
478→
479→  ipcMain.handle("browser:forward", (_e, { label }: { label: string }) => {
480→    const view = views.get(label);
481→    if (view?.webContents.canGoForward()) {
482→      view.webContents.goForward();
483→    }
484→  });
485→
486→  // -------------------------------------------------------------------------
487→  // Detached Browser Window
488→  // Renderer calls: invoke("browser:createDetachedWindow", { url, title, width, height, minWidth, minHeight })
489→  //                 invoke("browser:closeDetachedWindow")
490→  // -------------------------------------------------------------------------
491→
492→  ipcMain.handle(
493→    "browser:createDetachedWindow",
494→    (
495→      _e,
496→      {
497→        url,
498→        title,
499→        width,
500→        height,
501→        minWidth,
502→        minHeight,
503→      }: {
504→        url: string;
505→        title: string;
506→        width: number;
507→        height: number;
508→        minWidth?: number;
509→        minHeight?: number;
510→      }
511→    ) => {
512→      // Close existing detached window if any
513→      if (detachedWindow && !detachedWindow.isDestroyed()) {
514→        detachedWindow.close();
515→        detachedWindow = null;
516→      }
517→
518→      detachedWindow = new BrowserWindow({
519→        width,
520→        height,
521→        minWidth: minWidth ?? 600,
522→        minHeight: minHeight ?? 400,
523→        title,
524→        titleBarStyle: process.platform === "darwin" ? "hiddenInset" : "default",
525→        trafficLightPosition: { x: 16, y: 18 },
526→        webPreferences: {
527→          preload: join(__dirname, "../preload/index.mjs"),
528→          contextIsolation: true,
529→          nodeIntegration: false,
530→          sandbox: false, // ESM preload (index.mjs) requires sandbox: false
531→        },
532→      });
533→
534→      // Load the renderer app with the detached window URL
535→      if (is.dev && process.env.ELECTRON_RENDERER_URL) {
536→        detachedWindow.loadURL(`${process.env.ELECTRON_RENDERER_URL}${url}`);
537→      } else {
538→        detachedWindow.loadFile(join(__dirname, "../renderer/index.html"), {
539→          search: url.includes("?") ? url.split("?")[1] : "",
540→        });
541→      }
542→
543→      detachedWindow.on("closed", () => {
544→        detachedWindow = null;
545→        // Notify the main renderer that the detached window was closed
546→        const mainWindow = BrowserWindow.getAllWindows()[0];
547→        if (mainWindow) {
548→          mainWindow.webContents.send("browser:detached-closed");
549→        }
550→      });
551→    }
552→  );
553→
554→  ipcMain.handle("browser:closeDetachedWindow", () => {
555→    if (detachedWindow && !detachedWindow.isDestroyed()) {
556→      detachedWindow.close();
557→      detachedWindow = null;
558→    }
559→  });
560→}
561→
562→/**
563→ * Clean up all browser views. Called on app quit.
564→ */
565→export function destroyAllBrowserViews(): void {
566→  const mainWindow = BrowserWindow.getAllWindows()[0];
567→  for (const [, view] of views) {
568→    if (mainWindow) {
569→      mainWindow.contentView.removeChildView(view);
570→    }
571→    (view.webContents as any).destroy?.();
572→  }
573→  views.clear();
574→
575→  if (detachedWindow && !detachedWindow.isDestroyed()) {
576→    detachedWindow.close();
577→    detachedWindow = null;
578→  }
579→}
