 26→  RefreshCw,
 27→  ChevronLeft,
 28→  ChevronRight,
 29→  Terminal,
 30→  MousePointer2,
 31→  X,
 32→  Cookie,
 33→  Check,
 34→  Loader2,
 35→  Trash2,
 36→  Camera,
 37→  Smartphone,
 38→  Monitor,
 39→} from "lucide-react";
 40→import { BrowserTabBar } from "./BrowserTabBar";
 41→import { BrowserTab } from "./BrowserTab";
 42→import type {
 43→  BrowserTabState,
 44→  BrowserTabHandle,
 45→  ConsoleLog,
 46→  PersistedBrowserTab,
 47→  ElementSelectedEvent,
 48→} from "../types";
 49→import { createBrowserTab, deriveTitleFromUrl, hydratePersistedTab } from "../types";
 50→import { workspaceLayoutActions } from "@/features/workspace/store/workspaceLayoutStore";
 51→import { chatInsertActions } from "@/shared/stores/chatInsertStore";
 52→import { native } from "@/platform";
 53→
 54→const MAX_LOGS = 500;
 55→const PERSIST_DEBOUNCE_MS = 300;
 56→
 57→/** Browser info from get_cookie_browsers IPC command */
 58→interface InstalledBrowser {
 59→  name: string;
 60→  keychain_service: string;
 61→  cookie_db_path: string;
 62→  available: boolean;
 63→}
 64→
 65→/** Decrypted cookie from sync_browser_cookies IPC command */
 66→interface DecryptedCookie {
 67→  name: string;
 68→  value: string;
 69→  domain: string;
 70→  path: string;
 71→  secure: boolean;
 72→  http_only: boolean;
 73→  same_site: string;
 74→  expires: number;
 75→}
 76→
 77→interface BrowserPanelProps {
 78→  workspaceId: string | null;
 79→  /** Whether the browser panel is the active (visible) right-side tab.
 80→   *  When false, the panel stays mounted (preserving webview instances)
 81→   *  but all native BrowserViews are hidden via IPC. */
 82→  panelVisible?: boolean;
 83→  onClose?: () => void;
 84→  /** Pop-out callback — shown as a button in the tab bar */
 85→  onDetach?: () => void;
 86→  /** Which Electron window hosts the child BrowserViews. Defaults to "main". */
 87→  windowLabel?: string;
 88→}
 89→
 90→export function BrowserPanel({
 91→  workspaceId,
 92→  panelVisible = true,
 93→  onClose: _onClose,
 94→  onDetach,
 95→  windowLabel,
 96→}: BrowserPanelProps) {
 97→  // --- Initialize tabs from persisted state or create a fresh empty tab ---
 98→  const [tabs, setTabs] = useState<BrowserTabState[]>(() => {
 99→    if (workspaceId) {
100→      const layout = workspaceLayoutActions.getLayout(workspaceId);
101→      if (layout.browserTabs.length > 0) {
102→        return layout.browserTabs.map((pt) => hydratePersistedTab(pt, workspaceId));
103→      }
104→    }
105→    return [createBrowserTab(workspaceId)];
106→  });
107→
108→  const [activeTabId, setActiveTabId] = useState<string>(() => {
109→    if (workspaceId) {
110→      const layout = workspaceLayoutActions.getLayout(workspaceId);
111→      if (layout.activeBrowserTabId && layout.browserTabs.length > 0) {
112→        // Find the tab with the persisted active ID
113→        const persisted = layout.browserTabs.find((t) => t.id === layout.activeBrowserTabId);
114→        if (persisted) return persisted.id;
115→      }
116→    }
117→    return tabs[0]?.id ?? "";
118→  });
119→
120→  // Imperative handles per tab
121→  const tabRefs = useRef<Map<string, BrowserTabHandle>>(new Map());
122→
123→  // Debounced persistence timer
124→  const persistTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
125→
126→  // Track previous workspaceId to detect switches
127→  const prevWorkspaceIdRef = useRef(workspaceId);
128→
129→  // Mobile viewport toggle — constrains webview width to 390px (iPhone 14 logical width)
130→  const [mobileView, setMobileView] = useState(false);
131→
132→  // Derived: active tab for nav bar state
133→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? null;
134→
135→  // --- Centralized webview visibility guard ---
136→  // Native WKWebViews render above the DOM, so CSS can't hide them.
137→  // Individual BrowserTabs manage their own show/hide via effects, but
138→  // race conditions during rapid tab switches can leave stale webviews
139→  // visible. This guard explicitly hides all non-active webviews whenever
140→  // the active tab or panel visibility changes — belt-and-suspenders.
141→  const tabInfoRef = useRef(tabs);
142→  tabInfoRef.current = tabs;
143→
144→  useEffect(() => {
145→    const currentTabs = tabInfoRef.current;
146→    for (const tab of currentTabs) {
147→      if (tab.id !== activeTabId || !panelVisible) {
148→        native.browserViews.hide(tab.webviewLabel).catch(() => {});
149→      }
150→    }
151→  }, [activeTabId, panelVisible]);
152→
153→  // --- Persist tab state to workspace layout store (debounced) ---
154→  const persistTabs = useCallback(
155→    (currentTabs: BrowserTabState[], currentActiveId: string) => {
156→      if (!workspaceId) return;
157→
158→      if (persistTimerRef.current) clearTimeout(persistTimerRef.current);
159→      persistTimerRef.current = setTimeout(() => {
160→        // Only persist tabs that have a loaded URL (skip empty new tabs)
161→        const persisted: PersistedBrowserTab[] = currentTabs
162→          .filter((t) => t.currentUrl)
163→          .map((t) => ({ id: t.id, url: t.currentUrl, title: t.title }));
164→
165→        workspaceLayoutActions.setLayout(workspaceId, {
166→          browserTabs: persisted,
167→          activeBrowserTabId: currentActiveId,
168→        });
169→      }, PERSIST_DEBOUNCE_MS);
170→    },
171→    [workspaceId]
172→  );
173→
174→  // Cleanup persist timer on unmount
175→  useEffect(() => {
176→    return () => {
177→      if (persistTimerRef.current) clearTimeout(persistTimerRef.current);
178→    };
179→  }, []);
180→
181→  // --- Swap tabs when workspaceId changes (workspace switch) ---
182→  // BrowserPanel stays mounted to preserve WKWebView lifecycle, so we
183→  // manually swap tab state instead of relying on remount.
184→  //
185→  // CRITICAL: We must explicitly close old native webviews BEFORE setting
186→  // new tabs. BrowserTab's unmount cleanup also calls close, but it's async
187→  // and races with the new workspace's webviews — causing overlapping webviews
188→  // (native webviews render above the DOM so CSS can't hide them).
189→  useEffect(() => {
190→    const prevId = prevWorkspaceIdRef.current;
191→    if (prevId === workspaceId) return;
192→
193→    // Flush pending persistence for the old workspace immediately
194→    if (persistTimerRef.current) {
195→      clearTimeout(persistTimerRef.current);
196→      persistTimerRef.current = null;
197→    }
198→    if (prevId) {
199→      // Persist current tabs to old workspace synchronously (no debounce)
200→      const persisted: PersistedBrowserTab[] = tabs
201→        .filter((t) => t.currentUrl)
202→        .map((t) => ({ id: t.id, url: t.currentUrl, title: t.title }));
203→      workspaceLayoutActions.setLayout(prevId, {
204→        browserTabs: persisted,
205→        activeBrowserTabId: activeTabId,
206→      });
207→    }
208→
209→    // Hide then close ALL old native webviews immediately (don't wait for BrowserTab unmount).
210→    // hide() is called first as a defensive measure — on macOS, WKWebView.close() may not
211→    // immediately remove the native view from the NSView hierarchy, but hide() reliably
212→    // sets [view setHidden:YES] which makes it invisible instantly.
213→    for (const tab of tabs) {
214→      native.browserViews.hide(tab.webviewLabel).catch(() => {});
215→      native.browserViews.close(tab.webviewLabel).catch(() => {});
216→    }
217→
218→    // Load tabs for the new workspace
219→    let newTabs: BrowserTabState[];
220→    let newActiveId: string;
221→
222→    if (workspaceId) {
223→      const layout = workspaceLayoutActions.getLayout(workspaceId);
224→      if (layout.browserTabs.length > 0) {
225→        newTabs = layout.browserTabs.map((pt) => hydratePersistedTab(pt, workspaceId));
226→        const persisted = layout.activeBrowserTabId
227→          ? layout.browserTabs.find((t) => t.id === layout.activeBrowserTabId)
228→          : null;
229→        newActiveId = persisted ? persisted.id : newTabs[0].id;
230→      } else {
231→        const fresh = createBrowserTab(workspaceId);
232→        newTabs = [fresh];
233→        newActiveId = fresh.id;
234→      }
235→    } else {
236→      const fresh = createBrowserTab(null);
237→      newTabs = [fresh];
238→      newActiveId = fresh.id;
239→    }
240→
241→    tabRefs.current.clear();
242→
243→    setTabs(newTabs);
244→    setActiveTabId(newActiveId);
245→    prevWorkspaceIdRef.current = workspaceId;
246→    // eslint-disable-next-line react-hooks/exhaustive-deps
247→  }, [workspaceId]);
248→
249→  // --- Tab operations ---
250→
251→  const addTab = useCallback(() => {
252→    const newTab = createBrowserTab(workspaceId);
253→    setTabs((prev) => {
254→      const next = [...prev, newTab];
255→      // Persist inside updater to avoid stale closure over `tabs`
256→      persistTabs(next, newTab.id);
257→      return next;
258→    });
259→    setActiveTabId(newTab.id);
260→  }, [workspaceId, persistTabs]);
261→
262→  const closeTab = useCallback(
263→    (closingTabId: string) => {
264→      // Close the native webview BEFORE removing from React state.
265→      // BrowserTab's unmount cleanup also calls close, but it's async and
266→      // races with re-render — the native WKWebView can remain visible
267→      // during the gap because it renders above the DOM.
268→      const closingTab = tabs.find((t) => t.id === closingTabId);
269→      if (closingTab) {
270→        native.browserViews.hide(closingTab.webviewLabel).catch(() => {});
271→        native.browserViews.close(closingTab.webviewLabel).catch(() => {});
272→      }
273→
274→      setTabs((prev) => {
275→        const idx = prev.findIndex((t) => t.id === closingTabId);
276→        const newTabs = prev.filter((t) => t.id !== closingTabId);
277→
278→        let nextActiveId = activeTabId;
279→        // Select neighbor when closing the active tab
280→        if (closingTabId === activeTabId) {
281→          if (newTabs.length > 0) {
282→            const nextIdx = Math.min(idx, newTabs.length - 1);
283→            nextActiveId = newTabs[nextIdx].id;
284→            setActiveTabId(nextActiveId);
285→          } else {
286→            nextActiveId = "";
287→            setActiveTabId("");
288→          }
289→        }
290→
291→        persistTabs(newTabs, nextActiveId);
292→        return newTabs;
293→      });
294→      tabRefs.current.delete(closingTabId);
295→    },
296→    [tabs, activeTabId, persistTabs]
297→  );
298→
299→  /**
300→   * Stable callback for BrowserTab children to update their tab state.
301→   * Auto-derives title from URL when a page finishes loading.
302→   * Triggers debounced persistence on meaningful changes.
303→   */
304→  const handleUpdateTab = useCallback(
305→    (tabId: string, updates: Partial<BrowserTabState>) => {
306→      setTabs((prev) => {
307→        const next = prev.map((t) => {
308→          if (t.id !== tabId) return t;
309→          const updated = { ...t, ...updates };
310→          // Auto-derive title when page finishes loading successfully
311→          if (updates.loading === false && !updates.error && updated.currentUrl) {
312→            updated.title = deriveTitleFromUrl(updated.currentUrl);
313→          }
314→          return updated;
315→        });
316→
317→        // Persist on URL or title changes (page load finish, title change, navigation)
318→        if (
319→          updates.currentUrl !== undefined ||
320→          updates.title !== undefined ||
321→          (updates.loading === false && !updates.error)
322→        ) {
323→          persistTabs(next, activeTabId);
324→        }
325→
326→        return next;
327→      });
328→    },
329→    [activeTabId, persistTabs]
330→  );
331→
332→  /** Stable callback for BrowserTab children to add console logs */
333→  const handleAddLog = useCallback((tabId: string, level: ConsoleLog["level"], message: string) => {
334→    setTabs((prev) =>
335→      prev.map((t) => {
336→        if (t.id !== tabId) return t;
337→        const next = [...t.consoleLogs, { timestamp: new Date(), level, message }];
338→        return {
339→          ...t,
340→          consoleLogs: next.length > MAX_LOGS ? next.slice(next.length - MAX_LOGS) : next,
341→        };
342→      })
343→    );
344→  }, []);
345→
346→  /** Dispatch element selection to the chat input via chatInsertStore.
347→   *  Only handles "element-selected" — "area-selected" is intentionally ignored
348→   *  since area selections have no element metadata to reference. */
349→  const handleElementSelected = useCallback(
350→    (_tabId: string, event: ElementSelectedEvent) => {
351→      if (event.type !== "element-selected" || !event.element || !workspaceId) return;
352→
353→      // Serialize Record<string, string> fields as semicolon-separated strings
354→      const serialize = (rec: Record<string, string> | undefined, sep: string) =>
355→        rec
356→          ? Object.entries(rec)
357→              .map(([k, v]) => `${k}${sep}${v}`)
358→              .join("; ")
359→          : undefined;
360→
361→      chatInsertActions.insertElement(workspaceId, {
362→        ref: event.ref ?? "",
363→        tagName: event.element.tagName,
364→        path: event.element.path,
365→        innerText: event.element.innerText,
366→        context: event.context,
367→        reactComponent: event.reactComponent?.name,
368→        file: event.reactComponent?.fileName ?? undefined,
369→        line: event.reactComponent?.lineNumber?.toString() ?? undefined,
370→        styles: serialize(event.element.styles, ": "),
371→        props: serialize(event.element.props, "="),
372→        attributes: serialize(event.element.attributes, "="),
373→        innerHTML: event.element.innerHTML,
374→      });
375→    },
376→    [workspaceId]
377→  );
378→
379→  /** Capture the active tab's BrowserView as PNG and dispatch to chat input */
380→  const handleScreenshot = useCallback(async () => {
381→    if (!activeTab?.webviewLabel || !activeTab.currentUrl || !workspaceId) return;
382→    try {
383→      const dataUrl = await native.browserViews.screenshot(activeTab.webviewLabel);
384→      if (!dataUrl) return;
385→      // capturePage().toDataURL() returns "data:image/png;base64,..." — strip prefix
386→      const base64 = dataUrl.replace(/^data:image\/\w+;base64,/, "");
387→      const binaryStr = atob(base64);
388→      const bytes = new Uint8Array(binaryStr.length);
389→      for (let i = 0; i < binaryStr.length; i++) {
390→        bytes[i] = binaryStr.charCodeAt(i);
391→      }
392→      const blob = new Blob([bytes], { type: "image/png" });
393→      const file = new File([blob], `browser-screenshot-${Date.now()}.png`, { type: "image/png" });
394→      chatInsertActions.insertFiles(workspaceId, [file]);
395→    } catch (err) {
396→      console.error("Browser screenshot failed:", err);
397→    }
398→  }, [activeTab?.webviewLabel, activeTab?.currentUrl, workspaceId]);
399→
400→  // --- Navigation (operates on active tab) ---
401→
402→  const handleNavigate = useCallback(() => {
403→    if (!activeTab) return;
404→    const targetUrl = activeTab.url;
405→    if (!targetUrl) return;
406→
407→    let fullUrl = targetUrl;
408→    if (
409→      !targetUrl.startsWith("http://") &&
410→      !targetUrl.startsWith("https://") &&
411→      !targetUrl.startsWith("file://")
412→    ) {
413→      fullUrl = "https://" + targetUrl;
414→    }
415→
416→    const title = deriveTitleFromUrl(fullUrl);
417→
418→    // Truncate forward history and add new entry
419→    const newHistory = activeTab.history.slice(0, activeTab.historyIndex + 1);
420→    newHistory.push(fullUrl);
421→
422→    handleUpdateTab(activeTab.id, {
423→      url: fullUrl,
424→      currentUrl: fullUrl,
425→      loading: true,
426→      error: null,
427→      injected: false,
428→      title,
429→      history: newHistory,
430→      historyIndex: newHistory.length - 1,
431→    });
432→
433→    handleAddLog(activeTab.id, "info", `Navigating to: ${fullUrl}`);
434→    tabRefs.current.get(activeTab.id)?.navigateToUrl(fullUrl);
435→  }, [activeTab, handleUpdateTab, handleAddLog]);
436→
437→  const handleGoBack = useCallback(() => {
438→    if (!activeTab || activeTab.historyIndex <= 0) return;
439→    const newIndex = activeTab.historyIndex - 1;
440→    const previousUrl = activeTab.history[newIndex];
441→
442→    handleUpdateTab(activeTab.id, {
443→      url: previousUrl,
444→      currentUrl: previousUrl,
445→      historyIndex: newIndex,
446→      loading: true,
447→      error: null,
448→      injected: false,
449→      title: deriveTitleFromUrl(previousUrl),
450→    });
451→
452→    tabRefs.current.get(activeTab.id)?.goBack();
453→  }, [activeTab, handleUpdateTab]);
454→
455→  const handleGoForward = useCallback(() => {
456→    if (!activeTab || activeTab.historyIndex >= activeTab.history.length - 1) return;
457→    const newIndex = activeTab.historyIndex + 1;
458→    const nextUrl = activeTab.history[newIndex];
459→
460→    handleUpdateTab(activeTab.id, {
461→      url: nextUrl,
462→      currentUrl: nextUrl,
463→      historyIndex: newIndex,
464→      loading: true,
465→      error: null,
466→      injected: false,
467→      title: deriveTitleFromUrl(nextUrl),
468→    });
469→
470→    tabRefs.current.get(activeTab.id)?.goForward();
471→  }, [activeTab, handleUpdateTab]);
472→
473→  const handleReload = useCallback(() => {
474→    if (!activeTab) return;
475→    tabRefs.current.get(activeTab.id)?.reload();
476→  }, [activeTab]);
477→
478→  const handleToggleSelector = useCallback(() => {
479→    if (!activeTab) return;
480→    tabRefs.current.get(activeTab.id)?.toggleElementSelector();
481→  }, [activeTab]);
482→
483→  const handleKeyDown = useCallback(
484→    (e: React.KeyboardEvent<HTMLInputElement>) => {
485→      if (e.key === "Enter") handleNavigate();
486→    },
487→    [handleNavigate]
488→  );
489→
490→  const handleUrlChange = useCallback(
491→    (e: React.ChangeEvent<HTMLInputElement>) => {
492→      if (activeTab) {
493→        handleUpdateTab(activeTab.id, { url: e.target.value });
494→      }
495→    },
496→    [activeTab, handleUpdateTab]
497→  );
498→
499→  // Persist active tab ID changes — read tabs from ref to avoid stale closure
500→  const handleTabSelect = useCallback(
501→    (tabId: string) => {
502→      setActiveTabId(tabId);
503→      persistTabs(tabInfoRef.current, tabId);
504→    },
505→    [persistTabs]
506→  );
507→
508→  // --- Cookie Sync ---
509→
510→  const [cookieBrowsers, setCookieBrowsers] = useState<InstalledBrowser[]>([]);
511→  const [cookieSyncing, setCookieSyncing] = useState<string | null>(null); // browser name being synced
512→  const [lastSyncResult, setLastSyncResult] = useState<{ browser: string; count: number } | null>(
513→    null
514→  );
515→
516→  /** Fetch available browsers when dropdown opens.
517→   *  Requires Electron native handler with macOS Keychain access for cookie decryption.
518→   *  Degrades gracefully to empty list when unavailable (web dev mode). */
519→  const handleCookieDropdownOpen = useCallback(async () => {
520→    try {
521→      const browsers = (await native.browserViews.getCookieBrowsers()) as InstalledBrowser[];
522→      setCookieBrowsers(browsers);
523→    } catch (err) {
524→      console.warn("[Browser] Cookie import unavailable (requires Electron native handler):", err);
525→      setCookieBrowsers([]);
526→    }
527→  }, []);
528→
529→  /** Sync cookies from a browser for the active tab's domain, inject natively, and reload.
530→   *  Requires Electron native handlers: sync_browser_cookies (Keychain decryption)
531→   *  and inject_browser_cookies (WKHTTPCookieStore injection). */
532→  const handleCookieSync = useCallback(
533→    async (browserName: string) => {
534→      if (!activeTab?.currentUrl) return;
535→
536→      let domain: string;
537→      try {
538→        domain = new URL(activeTab.currentUrl).hostname;
539→      } catch {
540→        handleAddLog(activeTab.id, "error", "Invalid URL — can't extract domain for cookie sync");
541→        return;
542→      }
543→
544→      setCookieSyncing(browserName);
545→      handleAddLog(activeTab.id, "info", `Syncing cookies from ${browserName} for ${domain}...`);
546→
547→      try {
548→        const cookies = (await native.browserViews.syncCookies(
549→          browserName,
550→          domain
551→        )) as DecryptedCookie[];
552→
553→        if (cookies.length === 0) {
554→          handleAddLog(activeTab.id, "warn", `No cookies found in ${browserName} for ${domain}`);
555→          setCookieSyncing(null);
556→          return;
557→        }
558→
559→        // Inject ALL cookies (including HttpOnly) via native WKHTTPCookieStore
560→        const injected = await native.browserViews.injectCookies(activeTab.webviewLabel, cookies);
561→
562→        handleAddLog(
563→          activeTab.id,
564→          "info",
565→          `Injected ${injected}/${cookies.length} cookies from ${browserName}`
566→        );
567→
568→        setLastSyncResult({ browser: browserName, count: injected });
569→
570→        // Reload the page so the browser sends cookies with new requests
571→        if (injected > 0) {
572→          tabRefs.current.get(activeTab.id)?.reload();
573→          handleAddLog(activeTab.id, "info", "Reloading page with injected cookies...");
574→        }
575→      } catch (err) {
576→        // Cookie sync requires Electron native handlers with Keychain access.
577→        // In web dev mode, invoke() throws — log warning instead of error.
578→        console.warn("[Browser] Cookie sync failed (requires Electron native handler):", err);
579→        handleAddLog(activeTab.id, "error", `Cookie sync failed: ${err}`);
580→      } finally {
581→        setCookieSyncing(null);
582→      }
583→    },
584→    [activeTab, handleAddLog]
585→  );
586→
587→  /** Clear cookies by navigating to about:blank and back (resets WKHTTPCookieStore) */
588→  const handleClearCookies = useCallback(() => {
589→    if (!activeTab?.currentUrl) return;
590→    const restoreUrl = activeTab.currentUrl;
591→    const handle = tabRefs.current.get(activeTab.id);
592→    if (!handle) return;
593→
594→    handleAddLog(activeTab.id, "info", "Clearing site data...");
595→    setLastSyncResult(null);
596→
597→    // Navigate to blank page (clears cookie association), then back
598→    handle.navigateToUrl("about:blank");
599→    setTimeout(() => {
600→      handle.navigateToUrl(restoreUrl);
601→      handleAddLog(activeTab.id, "info", "Reloaded without cookies");
602→    }, 200);
603→  }, [activeTab, handleAddLog]);
604→
605→  // Ref setter callback — stores/removes imperative handle per tab
606→  const setTabRef = useCallback(
607→    (tabId: string) => (handle: BrowserTabHandle | null) => {
608→      if (handle) {
609→        tabRefs.current.set(tabId, handle);
610→      } else {
611→        tabRefs.current.delete(tabId);
612→      }
613→    },
614→    []
615→  );
616→
617→  return (
618→    <div className="flex h-full flex-col overflow-hidden">
619→      {/* Tab Bar */}
620→      <BrowserTabBar
621→        tabs={tabs}
622→        activeTabId={activeTabId}
623→        onTabSelect={handleTabSelect}
624→        onTabClose={closeTab}
625→        onTabAdd={addTab}
626→        onDetach={onDetach}
627→      />
628→
629→      {/* Navigation Bar — h-9 to align with chat tabs row */}
630→      <div className="border-border-subtle flex h-9 flex-shrink-0 items-center gap-2 border-b px-2">
631→        <Button
632→          variant="ghost"
633→          size="icon"
634→          className="h-7 w-7"
635→          onClick={handleGoBack}
636→          disabled={!activeTab || activeTab.loading || activeTab.historyIndex <= 0}
637→          title="Go back"
638→          aria-label="Go back"
639→        >
640→          <ChevronLeft className="h-4 w-4" />
641→        </Button>
642→
643→        <Button
644→          variant="ghost"
645→          size="icon"
646→          className="h-7 w-7"
647→          onClick={handleGoForward}
