 68→export function MainContent({
 69→  selectedWorkspace,
 70→  prStatus,
 71→  ghStatus,
 72→  workspaceChatPanelRef,
 73→  onCreateWorkspace: _onCreateWorkspace,
 74→  onOpenProject,
 75→  onCloneRepository,
 76→  repos,
 77→  onStartWorkspace,
 78→}: MainContentProps) {
