 83→  const {
 84→    contentTab,
 85→    setContentTab,
 86→    chatPanelCollapsed,
 87→    setChatPanelCollapsed,
 88→    contentPanelCollapsed,
 89→    setContentPanelCollapsed,
 90→  } = useWorkspaceLayout(selectedWorkspaceId);
 91→
