 99→  const connectionState = useConnectionState().state;
100→  const isDisconnected = connectionState === "disconnected";
101→
102→  // --- Workspace actions (PR bridge, archive, retry, manifest) ---
103→  const {
104→    createPRHandler,
105→    setCreatePRHandler,
106→    sendAgentMessageHandler,
107→    setSendAgentMessageHandler,
108→    selectedTargetBranch,
109→    setSelectedTargetBranch,
110→    handleCreatePR,
111→    handleSendAgentMessage,
112→    handleArchive,
