114→    handleViewSetupLogs,
115→    manifestTasks,
116→    hasManifest,
117→    handleRunTask,
118→  } = useWorkspaceActions({
119→    selectedWorkspace,
120→    setContentTab,
121→  });
122→
123→  const statusMutation = useUpdateWorkspaceStatus();
124→
125→  // Only start watching and querying diffs once the worktree checkout is complete.
126→  const isReady = selectedWorkspace?.state === "ready";
127→
128→  // Watch workspace for file changes (event-driven cache invalidation)
129→  const isWatched = useFileWatcher(
130→    isReady ? (selectedWorkspace?.workspace_path ?? null) : null,
131→    isReady ? selectedWorkspaceId : null
132→  );
133→
134→  // --- Refs for imperative panel control ---
135→  const chatPanelRef = useRef<ImperativePanelHandle>(null);
136→  const contentPanelRef = useRef<ImperativePanelHandle>(null);
137→  const panelGroupContainerRef = useRef<HTMLDivElement>(null);
138→
139→  // Dynamic collapsed size: 36px strip -> percentage of container width.
140→  const MIN_PANEL_SIZE = 15;
141→  const collapsedSizePct = useCollapsedSizePercent(panelGroupContainerRef, 36);
142→  const safeCollapsedSize = Math.min(collapsedSizePct, MIN_PANEL_SIZE - 0.1);
143→
144→  // Default split: 40% session / 60% content — same for all tabs.
145→  const sessionPanelDefaultSize = 40;
146→  const contentPanelDefaultSize = 60;
147→
148→  const sessionStatus = selectedWorkspace?.session_status;
149→  const isSessionWorking = sessionStatus === "working";
150→
151→  // --- Content tab change ---
152→  const handleContentTabChange = useCallback(
153→    (tab: ContentTab) => {
154→      setContentTab(tab);
155→      // Track feature surface adoption — fire on every user-initiated tab switch.
156→      // We use a static map instead of ts-pattern here because these are all
157→      // simple string→event mappings with no branching logic.
158→      const tabEventMap: Partial<Record<ContentTab, () => void>> = {
159→        terminal: () =>
160→          track("terminal_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
161→        browser: () => track("browser_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
162→        simulator: () =>
163→          track("simulator_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
164→        changes: () => track("diff_viewed", { workspace_id: selectedWorkspaceId ?? undefined }),
165→        files: () => track("files_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
166→      };
167→      tabEventMap[tab]?.();
168→    },
169→    [setContentTab, selectedWorkspaceId]
170→  );
171→
172→  // --- Chat panel collapse/expand ---
173→  const handleCollapseChatPanel = useCallback(() => {
174→    setChatPanelCollapsed(true);
175→    chatPanelRef.current?.collapse();
176→  }, [setChatPanelCollapsed]);
177→
178→  const handleExpandChatPanel = useCallback(() => {
179→    setChatPanelCollapsed(false);
180→  }, [setChatPanelCollapsed]);
181→
182→  // --- Content panel collapse/expand ---
183→  const handleCollapseContentPanel = useCallback(() => {
184→    setContentPanelCollapsed(true);
185→    contentPanelRef.current?.collapse();
186→  }, [setContentPanelCollapsed]);
187→
188→  const handleExpandContentPanel = useCallback(() => {
189→    setContentPanelCollapsed(false);
190→  }, [setContentPanelCollapsed]);
191→
192→  // --- Keyboard shortcuts ---
193→  usePanelShortcuts({
194→    enabled: selectedWorkspace !== null && !isMobile,
195→    chatPanelCollapsed,
196→    chatPanelRef,
197→    contentPanelCollapsed,
198→    contentPanelRef,
199→  });
200→
201→  // --- Reset panel sizes on workspace switch ---
202→  // ResizablePanelGroup has no key prop — it stays mounted across workspace
203→  // switches so SimulatorPanel and BrowserPanel keep their native sessions alive.
204→  // Without the key, react-resizable-panels won't re-apply defaultSize on
205→  // re-render. We must imperatively collapse/expand panels to match the
206→  // per-workspace Zustand state when the selected workspace changes.
207→  useEffect(() => {
208→    if (!selectedWorkspaceId) return;
209→    if (chatPanelCollapsed) {
210→      chatPanelRef.current?.collapse();
211→    } else {
212→      chatPanelRef.current?.expand();
213→      chatPanelRef.current?.resize(sessionPanelDefaultSize);
214→    }
215→    if (contentPanelCollapsed) {
216→      contentPanelRef.current?.collapse();
217→    } else {
218→      contentPanelRef.current?.expand();
219→      contentPanelRef.current?.resize(contentPanelDefaultSize);
220→    }
221→    // eslint-disable-next-line react-hooks/exhaustive-deps -- only fire on workspace change, not on collapse toggles
222→  }, [selectedWorkspaceId]);
223→
224→  // --- Hide all native BrowserViews on workspace switch ---
225→  // BrowserViews are native Electron overlays rendered ABOVE the DOM. When
226→  // switching workspaces or going to the welcome screen, stale views from
227→  // the previous workspace would remain visible. Hide them immediately;
228→  // the new workspace's BrowserTab will re-show its own view when ready.
229→  useEffect(() => {
230→    native.browserViews.hideAll().catch(() => {});
231→  }, [selectedWorkspaceId]);
232→
233→  // --- Sync workspace changes to detached browser window ---
234→  const detachedWorkspaceContext = useMemo(
235→    () =>
236→      selectedWorkspace
237→        ? {
238→            workspaceId: selectedWorkspace.id,
239→            directoryName: selectedWorkspace.slug,
240→            repoName: selectedWorkspace.repo_name,
241→            branch: selectedWorkspace.git_branch,
242→          }
243→        : null,
244→    [selectedWorkspace]
245→  );
246→
247→  useEffect(() => {
248→    if (!isBrowserDetached || !detachedWorkspaceContext) return;
249→    void native.events.send(BROWSER_WORKSPACE_CHANGE, detachedWorkspaceContext);
250→  }, [isBrowserDetached, detachedWorkspaceContext]);
251→
252→  // Insert code review prompt into chat input
253→  const handleInsertReviewPrompt = useCallback(() => {
254→    workspaceChatPanelRef.current?.insertText(REVIEW_CODE);
255→  }, [workspaceChatPanelRef]);
256→
257→  return (
258→    <SidebarInset className="min-w-0">
259→      {/* Connection banner — appears at top of content area when WS is down */}
260→      <ConnectionBanner />
261→
262→      <div
263→        data-slot="main-content"
264→        className={cn(
265→          "bg-bg-surface flex h-full min-w-0 flex-1 overflow-hidden border transition-[border-radius,border-color,opacity] duration-[280ms] ease-[cubic-bezier(.19,1,.22,1)]",
266→          sidebarOpen
267→            ? "border-border-subtle rounded-l-xl border-r-0"
268→            : "rounded-none border-transparent",
269→          isDisconnected && "opacity-60"
270→        )}
271→      >
272→        {/* Sidebar toggle -- visible when sidebar collapsed (desktop) or always on mobile welcome */}
273→        {(!sidebarOpen || isMobile) && !selectedWorkspace && (
274→          <button
275→            type="button"
276→            data-slot="welcome-sidebar-toggle"
277→            aria-label="Expand sidebar"
278→            onClick={toggleSidebar}
279→            className="text-muted-foreground/60 hover:text-foreground hover:bg-foreground/5 absolute top-3 left-3 z-10 flex h-7 w-7 items-center justify-center rounded-lg transition-[transform,color,background-color] duration-200 ease-out"
280→          >
281→            <PanelLeft className="h-4 w-4" />
282→          </button>
283→        )}
284→
285→        {selectedWorkspace ? (
286→          isMobile ? (
287→            /* Mobile: single-panel layout with bottom tab bar */
288→            <MobileLayout
289→              key={selectedWorkspace.id}
290→              workspace={selectedWorkspace}
291→              workspaceChatPanelRef={workspaceChatPanelRef}
292→              sendAgentMessageHandler={sendAgentMessageHandler}
293→              handleSendAgentMessage={handleSendAgentMessage}
294→              onRetrySetup={
295→                selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined
296→              }
297→              onViewSetupLogs={
298→                selectedWorkspace.setup_status === "failed" ? handleViewSetupLogs : undefined
299→              }
300→              setCreatePRHandler={setCreatePRHandler}
301→              setSendAgentMessageHandler={setSendAgentMessageHandler}
302→              isWatched={isWatched}
303→              manifestTasks={manifestTasks}
304→              hasManifest={hasManifest}
305→              onRunTask={handleRunTask}
306→              onStatusChange={(status) =>
307→                statusMutation.mutate({ workspaceId: selectedWorkspace.id, status })
308→              }
309→              prStatus={prStatus}
