  1→export interface ConsoleLog {
  2→  timestamp: Date;
  3→  level: "info" | "warn" | "error" | "debug";
  4→  message: string;
  5→}
  6→
  7→/** Lightweight tab state persisted in the workspace layout store.
  8→ *  Only what's needed to restore a tab — webviews are destroyed/recreated. */
  9→export interface PersistedBrowserTab {
 10→  id: string;
 11→  url: string; // last loaded URL
 12→  title: string; // display title
 13→}
 14→
 15→export interface BrowserTabState {
 16→  id: string;
 17→  /** Unique label for the native Electron BrowserView instance */
 18→  webviewLabel: string;
 19→  /** Display title: auto-derived from URL domain, overridden by native title events */
 20→  title: string;
 21→  /** Value in URL input bar */
 22→  url: string;
 23→  /** Currently loaded URL in the webview */
 24→  currentUrl: string;
 25→  /** Navigation history stack */
 26→  history: string[];
 27→  /** Current position in history */
 28→  historyIndex: number;
 29→  /** Whether iframe is loading */
 30→  loading: boolean;
 31→  /** Error message if page load failed */
 32→  error: string | null;
 33→  /** Whether automation script has been injected */
 34→  injected: boolean;
 35→  /** Whether automation injection failed (shown as error indicator) */
 36→  injectionFailed: boolean;
 37→  /** Whether element selector mode is active */
 38→  selectorActive: boolean;
 39→  /** Whether DevTools inspector is docked (stolen NSView in main window) */
 40→  devtoolsOpen: boolean;
 41→  /** Console logs for this tab */
 42→  consoleLogs: ConsoleLog[];
 43→}
 44→
 45→/** Data emitted when user selects an element in inspect mode */
 46→export interface ElementSelectedEvent {
 47→  type: "element-selected" | "area-selected";
 48→  ref?: string;
 49→  /** "local" = own dev server (localhost), "external" = any other website */
 50→  context?: "local" | "external";
 51→  element?: {
 52→    tagName: string;
 53→    id?: string;
 54→    className?: string;
 55→    innerText?: string;
 56→    path: string;
 57→    rect: { top: number; left: number; width: number; height: number };
 58→    /** Context-aware CSS: var() tokens for local, visual props for external */
 59→    styles: Record<string, string>;
 60→    /** Serialized React props — primitives only (variant, size, disabled, etc.) */
 61→    props?: Record<string, string>;
 62→    /** Whitelisted HTML attributes (data-testid, href, type, role, aria-label, etc.) */
 63→    attributes?: Record<string, string>;
 64→    /** Shallow innerHTML capped at 500 chars — shows element structure */
 65→    innerHTML?: string;
 66→  };
 67→  reactComponent?: {
 68→    name: string;
 69→    fileName: string | null;
 70→    lineNumber: number | null;
 71→  };
 72→  bounds?: { x: number; y: number; width: number; height: number };
 73→  url: string;
 74→  timestamp: number;
 75→}
 76→
 77→/** Imperative methods exposed by BrowserTab via forwardRef */
 78→export interface BrowserTabHandle {
 79→  navigateToUrl: (url: string) => void;
 80→  /** Native session history back — preserves scroll/form state */
 81→  goBack: () => void;
 82→  /** Native session history forward — preserves scroll/form state */
 83→  goForward: () => void;
 84→  reload: () => void;
 85→  injectAutomation: () => Promise<void>;
 86→  toggleElementSelector: () => void;
 87→  /** Force re-sync native webview position to placeholder bounds.
 88→   *  Call when the container layout shifts without a size change
 89→   *  (e.g., mobile view toggle repositions via flex centering). */
 90→  syncBounds: () => void;
 91→}
 92→
 93→/** Extract a readable title from a URL (domain or localhost:port) */
 94→export function deriveTitleFromUrl(url: string): string {
 95→  if (!url) return "New Tab";
 96→  try {
 97→    const parsed = new URL(url);
 98→    if (parsed.hostname === "localhost") {
 99→      return `localhost${parsed.port ? ":" + parsed.port : ""}`;
100→    }
101→    return parsed.hostname.replace(/^www\./, "");
102→  } catch {
103→    return "New Tab";
104→  }
105→}
106→
107→/** Create a fresh browser tab with default state.
108→ *  When workspaceId is provided, scopes the webview label to prevent
109→ *  collisions across workspaces. */
110→export function createBrowserTab(workspaceId?: string | null): BrowserTabState {
111→  const rand = Math.random().toString(36).slice(2, 6);
112→  const id = workspaceId
113→    ? `ws-${workspaceId.slice(0, 8)}-tab-${Date.now()}-${rand}`
114→    : `browser-tab-${Date.now()}-${rand}`;
115→  return {
116→    id,
117→    webviewLabel: id,
118→    title: "New Tab",
119→    url: "",
120→    currentUrl: "",
121→    history: [],
122→    historyIndex: -1,
123→    loading: false,
124→    error: null,
125→    injected: false,
126→    injectionFailed: false,
127→    selectorActive: false,
128→    devtoolsOpen: false,
129→    consoleLogs: [],
130→  };
131→}
132→
133→/** Hydrate a PersistedBrowserTab into a full BrowserTabState with
134→ *  ephemeral defaults (loading, history, consoleLogs, etc.) */
135→export function hydratePersistedTab(
136→  persisted: PersistedBrowserTab,
137→  workspaceId?: string | null
138→): BrowserTabState {
139→  const rand = Math.random().toString(36).slice(2, 6);
140→  // Create a new webview label (old webview is destroyed, new one will be created)
141→  const webviewLabel = workspaceId
142→    ? `ws-${workspaceId.slice(0, 8)}-tab-${Date.now()}-${rand}`
143→    : `browser-tab-${Date.now()}-${rand}`;
144→  return {
145→    id: persisted.id,
146→    webviewLabel,
147→    title: persisted.title || deriveTitleFromUrl(persisted.url),
148→    url: persisted.url,
149→    currentUrl: persisted.url,
150→    history: persisted.url ? [persisted.url] : [],
151→    historyIndex: persisted.url ? 0 : -1,
152→    loading: false,
153→    error: null,
154→    injected: false,
155→    injectionFailed: false,
156→    selectorActive: false,
157→    devtoolsOpen: false,
158→    consoleLogs: [],
159→  };
160→}
