789→                  return null;
790→                }
791→              })()}
792→
793→            <DropdownMenuLabel className="text-xs">Import Cookies</DropdownMenuLabel>
794→            <DropdownMenuSeparator />
795→            {cookieBrowsers.length === 0 ? (
796→              <DropdownMenuItem disabled className="text-xs">
797→                No browsers detected
798→              </DropdownMenuItem>
799→            ) : (
800→              cookieBrowsers.map((b) => (
801→                <DropdownMenuItem
802→                  key={b.name}
803→                  disabled={!b.available || !!cookieSyncing}
804→                  className="text-xs"
805→                  onClick={() => handleCookieSync(b.name)}
806→                >
807→                  <span className="flex-1">{b.name}</span>
808→                  {!b.available && (
809→                    <span className="text-muted-foreground text-2xs">Not installed</span>
810→                  )}
811→                  {b.available && cookieSyncing === b.name && (
812→                    <Loader2 className="h-3 w-3 animate-spin" />
813→                  )}
814→                  {b.available && !cookieSyncing && lastSyncResult?.browser === b.name && (
815→                    <span className="text-success text-2xs">{lastSyncResult.count} synced</span>
816→                  )}
817→                  {b.available && !cookieSyncing && lastSyncResult?.browser !== b.name && (
818→                    <Check className="text-muted-foreground/40 h-3 w-3" />
819→                  )}
820→                </DropdownMenuItem>
821→              ))
822→            )}
823→
824→            {/* Clear cookies option */}
825→            {activeTab?.currentUrl && (
826→              <>
827→                <DropdownMenuSeparator />
828→                <DropdownMenuItem
829→                  className="text-destructive text-xs"
830→                  onClick={handleClearCookies}
831→                  disabled={!!cookieSyncing}
832→                >
833→                  <Trash2 className="h-3.5 w-3.5" />
834→                  <span>Clear Site Data</span>
835→                </DropdownMenuItem>
836→              </>
837→            )}
838→          </DropdownMenuContent>
839→        </DropdownMenu>
840→
841→        <Button
842→          variant="ghost"
843→          size="icon"
844→          className="h-7 w-7"
845→          onClick={() => {
846→            if (!activeTab?.webviewLabel) return;
847→            if (activeTab.devtoolsOpen) {
848→              native.browserViews
849→                .closeDevtools(activeTab.webviewLabel)
850→                .then(() => handleUpdateTab(activeTab.id, { devtoolsOpen: false }))
851→                .catch((err) =>
852→                  handleAddLog(activeTab.id, "error", `Close devtools failed: ${err}`)
853→                );
854→            } else {
855→              native.browserViews
856→                .openDevtools(activeTab.webviewLabel)
857→                .then(() => handleUpdateTab(activeTab.id, { devtoolsOpen: true }))
858→                .catch((err) =>
859→                  handleAddLog(activeTab.id, "error", `Open devtools failed: ${err}`)
860→                );
861→            }
862→          }}
863→          disabled={!activeTab?.currentUrl}
864→          aria-pressed={activeTab?.devtoolsOpen}
865→          title={activeTab?.devtoolsOpen ? "Close DevTools" : "Open DevTools"}
866→          aria-label={activeTab?.devtoolsOpen ? "Close DevTools" : "Open DevTools"}
867→        >
868→          <Terminal className={`h-4 w-4 ${activeTab?.devtoolsOpen ? "text-primary" : ""}`} />
869→        </Button>
870→      </div>
871→
872→      {/* Tab content — devtools opens as floating window (docked not yet supported).
873→       * See open_browser_devtools in webview.rs for full history of docking attempts.
874→       *
875→       * Tab stacking uses CSS Grid (all tabs in [grid-area:1/1]) instead of
876→       * absolute positioning. Previous approach (absolute inset-0 on BrowserTab)
877→       * broke mobile view: the placeholder's getBoundingClientRect() returned
878→       * stale full-width values because absolute-positioned elements don't
879→       * reliably inherit width constraints from their containing block when
880→       * parent containers restructure (mx-auto, flex centering). Grid stacking
881→       * keeps tabs in normal flow so they inherit w-[390px] naturally and
882→       * ResizeObserver fires on actual size changes. */}
883→      <div className={`relative min-h-0 flex-1 overflow-hidden ${mobileView ? "bg-muted/30" : ""}`}>
884→        <div
885→          className={`grid h-full ${mobileView ? "border-border/40 mx-auto w-[390px] border-x" : "w-full"}`}
886→        >
887→          {tabs.length === 0 ? (
888→            <div className="text-muted-foreground/50 flex h-full items-center justify-center text-xs">
889→              Click + to open a browser tab
890→            </div>
891→          ) : (
892→            tabs.map((tab) => (
893→              <BrowserTab
894→                key={tab.id}
895→                ref={setTabRef(tab.id)}
896→                tab={tab}
897→                onUpdateTab={handleUpdateTab}
898→                onAddLog={handleAddLog}
899→                onElementSelected={handleElementSelected}
900→                visible={tab.id === activeTabId && panelVisible}
901→                windowLabel={windowLabel}
902→                mobileView={mobileView}
903→              />
904→            ))
905→          )}
906→        </div>
907→      </div>
