  // Collect labels, send one IPC call to stash the whole batch.
  if (prevId && tabs.length > 0) {
    const labels = tabs.map((t) => t.webviewLabel);
    native.browserViews.stashWorkspace(prevId, labels).catch(() => {
      // Stash failed — fall back to hiding (views will be recreated on next visit)
      for (const label of labels) {
        native.browserViews.hide(label).catch(() => {});
      }
    });
