The `enforceBudget` function would be a module-scoped helper:

```typescript
// BrowserPanel.tsx — module scope (outside component)

/** Track all stashed webview labels in insertion order (oldest first). */
const stashedLabels: string[] = [];

function enforceBudget(maxStashed: number, activeLabels: string[]): void {
  // Remove active labels from stash tracking (they're in use now)
  const activeSet = new Set(activeLabels);
  const stillStashed = stashedLabels.filter((l) => !activeSet.has(l));

  // Record any newly stashed labels
  // (The labels just stashed in step 2 that aren't in the new workspace)
  // Already tracked by the stash call

  if (stillStashed.length <= maxStashed) {
    stashedLabels.length = 0;
    stashedLabels.push(...stillStashed);
    return;
  }

  // Evict oldest beyond budget
  const toEvict = stillStashed.slice(0, stillStashed.length - maxStashed);
  const toKeep = stillStashed.slice(stillStashed.length - maxStashed);
  stashedLabels.length = 0;
  stashedLabels.push(...toKeep);

  if (toEvict.length > 0) {
    native.browserViews.evict(toEvict).catch(() => {});
  }
}
```

