#### BrowserPanel Workspace Switch Effect (renderer)

The core change. Replace the "destroy old, create new" logic with "park old, try restore new, fall back to create."

```typescript
// BrowserPanel.tsx — replace the workspace-switch useEffect (lines 189-247)

useEffect(() => {
  const prevId = prevWorkspaceIdRef.current;
  if (prevId === workspaceId) return;

  // 1. Flush pending persistence for old workspace
  if (persistTimerRef.current) {
    clearTimeout(persistTimerRef.current);
    persistTimerRef.current = null;
  }
  if (prevId) {
    const persisted: PersistedBrowserTab[] = tabs
      .filter((t) => t.currentUrl)
      .map((t) => ({ id: t.id, url: t.currentUrl, title: t.title }));
    workspaceLayoutActions.setLayout(prevId, {
      browserTabs: persisted,
      activeBrowserTabId: activeTabId,
    });
  }

  // 2. Park old workspace's views (don't destroy)
  if (prevId) {
    native.browserViews.parkWorkspace(prevId).catch(() => {});
  }

  // 3. Attempt to restore new workspace's parked views
  const restore = async () => {
    if (!workspaceId) {
      const fresh = createBrowserTab(null);
      tabRefs.current.clear();
      setTabs([fresh]);
      setActiveTabId(fresh.id);
      prevWorkspaceIdRef.current = workspaceId;
      return;
    }

    const existingLabels = await native.browserViews
      .getWorkspaceViewLabels(workspaceId)
      .catch(() => [] as string[]);

    const layout = workspaceLayoutActions.getLayout(workspaceId);

    if (existingLabels.length > 0 && layout.browserTabs.length > 0) {
      // Parked views exist -- unpark them and restore tab state with ORIGINAL labels
      await native.browserViews.unparkWorkspace(workspaceId).catch(() => {});

      const restoredTabs = layout.browserTabs.map((pt) => {
        // Find the existing label for this tab from the parked set
        // Tab IDs encode workspace prefix, so matching by tab id works
        const matchingLabel = existingLabels.find((l) => l.includes(pt.id.split("-tab-")[1] ?? ""));
        return restoreParkedTab(pt, matchingLabel ?? null, workspaceId);
      });

      const newActiveId = layout.activeBrowserTabId
        && restoredTabs.find((t) => t.id === layout.activeBrowserTabId)
        ? layout.activeBrowserTabId
        : restoredTabs[0]?.id ?? "";

      tabRefs.current.clear();
      setTabs(restoredTabs);
      setActiveTabId(newActiveId);
    } else {
      // No parked views — hydrate from localStorage (cold start path)
      let newTabs: BrowserTabState[];
      let newActiveId: string;

      if (layout.browserTabs.length > 0) {
        newTabs = layout.browserTabs.map((pt) => hydratePersistedTab(pt, workspaceId));
        const persisted = layout.activeBrowserTabId
          ? layout.browserTabs.find((t) => t.id === layout.activeBrowserTabId)
          : null;
        newActiveId = persisted ? persisted.id : newTabs[0].id;
      } else {
        const fresh = createBrowserTab(workspaceId);
        newTabs = [fresh];
        newActiveId = fresh.id;
      }

      tabRefs.current.clear();
      setTabs(newTabs);
      setActiveTabId(newActiveId);
    }

    prevWorkspaceIdRef.current = workspaceId;
  };

  restore();
}, [workspaceId]);
```

