#### New Type Helper: `restoreParkedTab` (types.ts)

When views are parked, we restore tab state with the **original webview label** (the view still exists in the main process). No new webview creation needed.

```typescript
/** Restore a tab whose native WebContentsView is still alive (parked).
 *  Keeps the original webviewLabel so no new view creation is needed.
 *  The BrowserTab component will detect webviewCreatedRef should be true
 *  and skip createWebviewIfNeeded. */
export function restoreParkedTab(
  persisted: PersistedBrowserTab,
  existingLabel: string | null,
  workspaceId: string
): BrowserTabState {
  if (!existingLabel) {
    // Fallback: label not found in parked set, hydrate as new
    return hydratePersistedTab(persisted, workspaceId);
  }
  return {
    id: persisted.id,
    webviewLabel: existingLabel,
    title: persisted.title || deriveTitleFromUrl(persisted.url),
    url: persisted.url,
    currentUrl: persisted.url,
    history: persisted.url ? [persisted.url] : [],
    historyIndex: persisted.url ? 0 : -1,
    loading: false,
    error: null,
    injected: false,       // will re-inject on show (page context survives park)
    injectionFailed: false,
    selectorActive: false,
    devtoolsOpen: false,
    consoleLogs: [],
  };
}
```

