```typescript
const MAX_PARKED_WORKSPACES = 3;
const workspaceLRU: string[] = []; // most recent at end

function touchWorkspace(workspaceId: string): void {
  const idx = workspaceLRU.indexOf(workspaceId);
  if (idx !== -1) workspaceLRU.splice(idx, 1);
  workspaceLRU.push(workspaceId);
}

function evictOldestIfNeeded(currentWorkspaceId: string): void {
  // Count parked workspaces (all except current)
  const parked = workspaceLRU.filter((id) => id !== currentWorkspaceId);
  while (parked.length > MAX_PARKED_WORKSPACES) {
    const evictId = parked.shift()!;
    // Destroy all views for this workspace
    const labels = workspaceViews.get(evictId);
    if (labels) {
      const mainWindow = BrowserWindow.getAllWindows()[0];
      for (const label of labels) {
        const view = views.get(label);
        if (view) {
          if (mainWindow) mainWindow.contentView.removeChildView(view);
          (view.webContents as any).destroy?.();
        }
        views.delete(label);
        viewBounds.delete(label);
        viewWorkspace.delete(label);
      }
      workspaceViews.delete(evictId);
    }
    const lruIdx = workspaceLRU.indexOf(evictId);
    if (lruIdx !== -1) workspaceLRU.splice(lruIdx, 1);
  }
}
```

