export function hydratePersistedTab(
  persisted: PersistedBrowserTab,
  workspaceId?: string | null
): BrowserTabState {
  // CRITICAL CHANGE: use the persisted tab's ID for the label, not a random one
  const label = workspaceId
    ? stableWebviewLabel(workspaceId, persisted.id)
    : `browser-${persisted.id}`;
  return {
    id: persisted.id,
    webviewLabel: label,  // STABLE — reconnects to parked native view
    // ... rest unchanged
  };
}
