**5. TTL Eviction** to prevent unbounded memory growth:

```typescript
const PARKED_VIEW_TTL_MS = 10 * 60 * 1000; // 10 minutes
const MAX_PARKED_VIEWS = 20;

function evictStaleParkedViews(): void {
  const now = Date.now();
  const mainWindow = BrowserWindow.getAllWindows()[0];

  for (const [label, parked] of parkedViews) {
    if (now - parked.parkedAt > PARKED_VIEW_TTL_MS) {
      if (mainWindow) {
        // Ensure it's not somehow still attached
        try { mainWindow.contentView.removeChildView(parked.view); } catch {}
      }
      (parked.view.webContents as any).destroy?.();
      parkedViews.delete(label);
      viewBounds.delete(label);
      // Clean up workspace index
      const wsLabels = workspaceViewIndex.get(parked.workspaceId);
      if (wsLabels) {
        wsLabels.delete(label);
        if (wsLabels.size === 0) workspaceViewIndex.delete(parked.workspaceId);
      }
    }
  }

  // LRU eviction if over budget
  if (parkedViews.size > MAX_PARKED_VIEWS) {
    const sorted = [...parkedViews.entries()].sort((a, b) => a[1].parkedAt - b[1].parkedAt);
    const toEvict = sorted.slice(0, parkedViews.size - MAX_PARKED_VIEWS);
    for (const [label, parked] of toEvict) {
      if (mainWindow) {
        try { mainWindow.contentView.removeChildView(parked.view); } catch {}
      }
      (parked.view.webContents as any).destroy?.();
      parkedViews.delete(label);
      viewBounds.delete(label);
    }
  }
}

// Run eviction check every 60 seconds
setInterval(evictStaleParkedViews, 60_000);
```

