export async function park(workspaceId: string): Promise<void> {
  if (!capabilities.nativeBrowser) return;
  await invoke("park_browser_webviews", { workspaceId });
}

export async function recall(
  label: string,
  bounds: { x: number; y: number; width: number; height: number }
): Promise<{ recalled: boolean; url: string | null }> {
  if (!capabilities.nativeBrowser) return { recalled: false, url: null };
  return invoke("recall_browser_webview", { label, ...bounds });
}

