`hydratePersistedTab` becomes:

```typescript
export function hydratePersistedTab(
  persisted: PersistedBrowserTab,
  workspaceId?: string | null
): BrowserTabState {
  // REUSE the persisted webviewLabel instead of generating a new one
  const webviewLabel = persisted.webviewLabel ?? generateWebviewLabel(workspaceId);
  return {
    id: persisted.id,
    webviewLabel,
    title: persisted.title || deriveTitleFromUrl(persisted.url),
    url: persisted.url,
    currentUrl: persisted.url,
    history: persisted.url ? [persisted.url] : [],
    historyIndex: persisted.url ? 0 : -1,
    loading: false,
    error: null,
    injected: false,
    injectionFailed: false,
    selectorActive: false,
    devtoolsOpen: false,
    consoleLogs: [],
  };
}

function generateWebviewLabel(workspaceId?: string | null): string {
  const rand = Math.random().toString(36).slice(2, 6);
  return workspaceId
    ? `ws-${workspaceId.slice(0, 8)}-tab-${Date.now()}-${rand}`
    : `browser-tab-${Date.now()}-${rand}`;
}
